interface UserSettings {
  theme: "light" | "dark";
  language: string;
  notifications: boolean;
  fontSize: number;
}

function updateSettings(current: UserSettings, updates: Partial<UserSettings>): UserSettings {
  return { ...current, ...updates };
}

