interface SignupForm {
  name?: string;
  email?: string;
  password?: string;
  confirmPassword?: string;
  agreeToTerms?: boolean;
}

function submitSignup(form: Required<SignupForm>): string {
  if (form.password !== form.confirmPassword) return "Passwords don't match";
  if (!form.agreeToTerms) return "Must accept terms";
  return `Account created for ${form.email}`;
}

const validForm: Required<SignupForm> = {
  name: "Alice", email: "alice@co.com",
  password: "secure123", confirmPassword: "secure123",
  agreeToTerms: true,
};

console.log(submitSignup(validForm));
console.log(submitSignup({ ...validForm, password: "other" }));

