function createUser(name: string, email: string, plan: "free" | "pro" = "free") {
  return {
    id: Math.floor(Math.random() * 1000),
    name, email, plan,
    createdAt: "2024-01-15",
    xp: 0,
  };
}

// Derive the return type from the function
type User = ReturnType<typeof createUser>;

function greetUser(user: User): string {
  return `Welcome, ${user.name}! Plan: ${user.plan}`;
}

const alice = createUser("Alice", "alice@co.com", "pro");
const bob   = createUser("Bob",   "bob@co.com");

console.log(greetUser(alice));
console.log(greetUser(bob));
console.log(`Alice XP: ${alice.xp}`);

function processPayment(
  userId: number,
  amount: number,
  currency: "USD" | "EUR" | "GBP",
  description: string
): { transactionId: string; status: string } {
  return { transactionId: `TX-${Date.now()}`, status: "pending" };
}

type PaymentArgs   = Parameters<typeof processPayment>;
type PaymentResult = ReturnType<typeof processPayment>;

function logPayment(args: PaymentArgs, result: PaymentResult): void {
  const [userId, amount, currency, description] = args;
  console.log(`TX ${result.transactionId}: $${amount} ${currency} for user ${userId}`);
  console.log(`  Desc: ${description} — ${result.status}`);
}

const args: PaymentArgs = [42, 99.99, "USD", "Pro Plan subscription"];
const result = processPayment(...args);
logPayment(args, result);

type HttpStatus = 200 | 201 | 204 | 400 | 401 | 403 | 404 | 500;
type SuccessStatus = Extract<HttpStatus, 200 | 201 | 204>;  // 200 | 201 | 204
type ErrorStatus   = Exclude<HttpStatus, 200 | 201 | 204>;  // 400 | 401 | 403 | 404 | 500

function isSuccess(code: HttpStatus): code is SuccessStatus {
  return code >= 200 && code < 300;
}

const responses: HttpStatus[] = [200, 201, 404, 500, 204, 401];
for (const code of responses) {
  if (isSuccess(code)) {
    const success: SuccessStatus = code;
    console.log(`✓ ${success}`);
  } else {
    const error: ErrorStatus = code;
    console.log(`✗ ${error}`);
  }
}

function filterDefined<T>(arr: (T | null | undefined)[]): NonNullable<T>[] {
  return arr.filter((v): v is NonNullable<T> => v !== null && v !== undefined);
}

function getFirstDefined<T>(values: (T | null | undefined)[]): NonNullable<T> | undefined {
  return filterDefined(values)[0];
}

const userIds = [1, null, 3, undefined, 5, null, 7];
const names   = ["Alice", undefined, null, "Bob", null, "Carol"];

const validIds = filterDefined(userIds);
const validNames = filterDefined(names);

console.log(`Valid IDs: ${validIds.join(", ")}`);
console.log(`Valid names: ${validNames.join(", ")}`);
console.log(`First name: ${getFirstDefined(names)}`);

class UserService {
  constructor(
    private apiUrl: string,
    private timeout: number,
    private debug: boolean
  ) {}

  getInfo(): string {
    return `UserService(${this.apiUrl}, ${this.timeout}ms, debug=${this.debug})`;
  }
}

type ServiceConstructorArgs = ConstructorParameters<typeof UserService>;
type ServiceInstance       = InstanceType<typeof UserService>;

function createService(
  ServiceClass: typeof UserService,
  ...args: ConstructorParameters<typeof UserService>
): ServiceInstance {
  return new ServiceClass(...args);
}

const args: ServiceConstructorArgs = [
  "https://api.example.com", 5000, false
];

const service = createService(UserService, ...args);
console.log(service.getInfo());

